import './index.css';
import React, { useState } from 'react';
import Header from "./components/Header";
import Sidebar from './components/Sidebar';
import TelaPeriodos from "./components/TelaPeriodos";
import TelaAlunos from "./components/TelaAlunos";
import TelaPacientes from "./components/TelaPacientes";
import TelaDisciplinas from "./components/TelaDisciplinas";
import TelaAgendamentos from "./components/TelaAgendamentos";
import { BrowserRouter as Router, Routes, Route, Navigate } from "react-router-dom";
import { UserProvider, useUser } from "./contexts/UserContext";
import Login from "./Login";
import DashboardAluno from "./DashboardAluno";
import DashboardRecepcao from "./DashboardRecepcao";
import DashboardDisciplinas from './DashboardDisciplinas';

// Permite acessar apenas se logado e (se for o caso) tipo correto
function ProtectedRoute({ children, tipo }) {
  const { user } = useUser();
  if (!user) return <Navigate to="/login" />;
  if (tipo && user.tipo !== tipo) return <Navigate to="/login" />;
  return children;
}

// Layout principal: Header, Sidebar e conteúdo
function LayoutInterno() {
  const [active, setActive] = useState('dashboard');

  // Renderiza o conteúdo principal baseado no menu lateral selecionado
  function renderConteudo() {
    switch (active) {
      case 'dashboard':
        return <DashboardDisciplinas />;
      case 'agendar':
        return <TelaAgendamentos />;
      case 'disciplinas':
        return <TelaDisciplinas />;
      case 'pacientes':
        return <TelaPacientes />;
      case 'alunos':
        return <TelaAlunos />;
      case 'periodos':
        return <TelaPeriodos />;
      default:
        return (
          <div>
            <h1 className="text-3xl font-bold mb-6">Página não encontrada</h1>
          </div>
        );
    }
  }

  return (
    <div className="bg-[#ffffff] min-h-screen">
      <Header />
      <div className="flex">
        <Sidebar active={active} onMenuClick={setActive} />
        <main className="flex-2 ml-64 mt-16 p-8 h-[calc(100vh-64px)] overflow-hidden">
          <div className="mx-auto">{renderConteudo()}</div>
        </main>
      </div>
    </div>
  );
}

// Decide qual dashboard mostrar
function Dashboards() {
  const { user } = useUser();
  if (user?.tipo === "admin") return <DashboardRecepcao />;
  return <DashboardAluno />;
}

// App principal
export default function App() {
  return (
    <UserProvider>
      <Router>
        <Routes>
          <Route path="/login" element={<Login />} />
          <Route
            path="/*"
            element={
              <ProtectedRoute>
                <LayoutInterno />
              </ProtectedRoute>
            }
          />
          <Route path="*" element={<Navigate to="/login" />} />
        </Routes>
      </Router>
    </UserProvider>
  );
}
